def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        complexity = 1.0
        oscillation = 1.0
        decay = 1.0
        bonus = 0.0
        penalty = 0.0
        for outer in range(1, 8):
            if outer % 2 == 0:
                complexity *= 1 + 0.03 * outer
            else:
                complexity *= 0.95 - 0.01 * outer
            for inner in range(1, 10):
                factor = np.sin(ratio * inner * outer) + np.cos(ratio * inner / (outer + 1))
                if factor > 0:
                    base_score += np.exp(-ratio * (inner + outer)) * complexity * factor
                else:
                    base_score += (np.log1p(inner * outer) + ratio ** 2) * complexity * abs(factor)
                if (cap + outer * inner) % 9 == 0:
                    oscillation *= 1.03
                    base_score *= 1.02
                elif (cap * inner) % 13 == 0:
                    oscillation *= 0.97
                    base_score *= 0.99
                if inner == 5 and outer > 3:
                    for sub in range(1, 5):
                        diff = cap - item * (sub ** 3) / (outer + 1)
                        if diff > 0:
                            if diff % (sub + outer) == 0:
                                bonus += np.log1p(diff) / (sub + 2)
                            else:
                                penalty += np.sqrt(abs(diff)) / (sub + outer + 1)
                        else:
                            penalty += abs(diff) ** 1.5 / (sub + 3)
                if outer + inner > 10:
                    decay *= 0.98 - 0.005 * (outer + inner)
                else:
                    decay *= 1.02 + 0.004 * (outer + inner)
                if ratio > 0.9 and inner % 2 == 0:
                    base_score *= 1.1 + 0.01 * inner
                elif ratio < 0.15 and outer % 3 == 0:
                    base_score *= 0.85 - 0.015 * outer
        score = (base_score + bonus - penalty) * oscillation * decay
        if score < 0:
            priorities[idx] = -score * (np.log1p(cap + item) ** 1.1 + np.sqrt(cap) * 1.05)
        else:
            if cap > item * 3:
                priorities[idx] = -score / (np.sqrt(cap) + 2) * (1 + ratio ** 1.5)
            else:
                priorities[idx] = -score / (cap + 5) * np.exp(-ratio ** 1.8)
        if ratio > 0.97:
            priorities[idx] *= 1.2
        elif ratio < 0.03:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 1.05
        elif cap % 5 == 0:
            priorities[idx] *= 0.93
        if abs(priorities[idx]) < 1e-5:
            priorities[idx] = np.inf
    return priorities
